class Solution {
    unordered_map<int,int> cnt;
    int dfs(TreeNode* n) {
        if (!n) return 0;
        int s = n->val + dfs(n->left) + dfs(n->right);
        cnt[s]++;
        return s;
    }
public:
    vector<int> findFrequentTreeSum(TreeNode* root) {
        dfs(root);
        int mx = 0;
        for (auto& p : cnt) mx = max(mx, p.second);
        vector<int> ans;
        for (auto& p : cnt) if (p.second == mx) ans.push_back(p.first);
        return ans;
    }
};
